/*@ requires \valid(tpm_handle);
    ensures \result ∈ {(TPM2_RC)0x000, (TSS2_RC)(7 << 16 | 11U)};
    ensures
      *\old(tpm_handle) ∈
      {\old(esys_handle), 0x40000001, 0x40000007, 0x4000000A, 0x4000000B,
       0x4000000C, 0x4000000D, 0x40000110 + (\old(esys_handle) - 0x120U),
       \at(*tpm_handle,Pre)};
    assigns *tpm_handle;
    
    behavior handle_1:
      assumes esys_handle ≤ 31U;
      ensures *\old(tpm_handle) ≡ \old(esys_handle);
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior handle_2:
      assumes esys_handle ≡ 0x101U;
      ensures *\old(tpm_handle) ≡ (TPM2_RH)0x40000001;
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior handle_3:
      assumes esys_handle ≡ 0x107U;
      ensures *\old(tpm_handle) ≡ (TPM2_RH)0x40000007;
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior handle_4:
      assumes esys_handle ≡ 0x10AU;
      ensures *\old(tpm_handle) ≡ (TPM2_RH)0x4000000A;
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior handle_5:
      assumes esys_handle ≡ 0x10BU;
      ensures *\old(tpm_handle) ≡ (TPM2_RH)0x4000000B;
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior handle_6:
      assumes esys_handle ≡ 0x10CU;
      ensures *\old(tpm_handle) ≡ (TPM2_RH)0x4000000C;
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior handle_7:
      assumes esys_handle ≡ 0x10DU;
      ensures *\old(tpm_handle) ≡ (TPM2_RH)0x4000000D;
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior handle_8:
      assumes esys_handle > 31U;
      assumes
        ¬(esys_handle ∈ {0x101U, 0x107U, 0x10AU, 0x10BU, 0x10CU, 0x10DU});
      assumes 0x120U ≤ esys_handle ≤ 0x12FU;
      ensures
        *\old(tpm_handle) ≡ 0x40000110 + (\old(esys_handle) - 0x120U);
      ensures \result ≡ (TPM2_RC)0x000;
    
    behavior wrong_handle:
      assumes esys_handle > 31U;
      assumes
        ¬(esys_handle ∈ {0x101U, 0x107U, 0x10AU, 0x10BU, 0x10CU, 0x10DU});
      assumes esys_handle < 0x120U ∨ esys_handle > 0x12FU;
      ensures *\old(tpm_handle) ≡ \at(*tpm_handle,Pre);
      ensures \result ≡ (TSS2_RC)(7 << 16 | 11U);
    
    complete behaviors wrong_handle,
                       handle_8,
                       handle_7,
                       handle_6,
                       handle_5,
                       handle_4,
                       handle_3,
                       handle_2,
                       handle_1;
    disjoint behaviors wrong_handle,
                       handle_8,
                       handle_7,
                       handle_6,
                       handle_5,
                       handle_4,
                       handle_3,
                       handle_2,
                       handle_1;
 */
TSS2_RC iesys_handle_to_tpm_handle(ESYS_TR esys_handle,
                                   TPM2_HANDLE *tpm_handle)
{
  TSS2_RC __retres;
  if (esys_handle <= 31U) {
    *tpm_handle = esys_handle;
    __retres = (TPM2_RC)0x000;
    goto return_label;
  }
  if (esys_handle == 0x101U) {
    *tpm_handle = (TPM2_RH)0x40000001;
    __retres = (TPM2_RC)0x000;
    goto return_label;
  }
  if (esys_handle == 0x107U) {
    *tpm_handle = (TPM2_RH)0x40000007;
    __retres = (TPM2_RC)0x000;
    goto return_label;
  }
  if (esys_handle == 0x10AU) {
    *tpm_handle = (TPM2_RH)0x4000000A;
    __retres = (TPM2_RC)0x000;
    goto return_label;
  }
  if (esys_handle == 0x10BU) {
    *tpm_handle = (TPM2_RH)0x4000000B;
    __retres = (TPM2_RC)0x000;
    goto return_label;
  }
  if (esys_handle == 0x10CU) {
    *tpm_handle = (TPM2_RH)0x4000000C;
    __retres = (TPM2_RC)0x000;
    goto return_label;
  }
  if (esys_handle == 0x10DU) {
    *tpm_handle = (TPM2_RH)0x4000000D;
    __retres = (TPM2_RC)0x000;
    goto return_label;
  }
  if (esys_handle >= 0x120U) 
    if (esys_handle <= 0x12FU) {
      *tpm_handle = (TPM2_RH)0x40000110 + (esys_handle - 0x120U);
      __retres = (TPM2_RC)0x000;
      goto return_label;
    }
  __retres = ((TSS2_RC)7 << 16) | 11U;
  return_label: return __retres;
}

