/*@ requires \valid(src) ∧ \valid(dest + (0 .. sizeof(*src) - 1));
    requires \separated(dest + (0 .. sizeof(*src) - 1), src);
    ensures \valid(\old(src));
    ensures \valid(\old(dest) + (0 .. sizeof(*\old(src)) - 1));
    assigns *(dest + (0 .. sizeof(*src) - 1));
 */
void memcpy_custom(uint8_t *dest, uint32_t *src, size_t n)
{
  *(dest + 3) = (uint8_t)(*src & (unsigned int)0xFF);
  *(dest + 2) = (uint8_t)((*src >> 8) & (unsigned int)0xFF);
  *(dest + 1) = (uint8_t)((*src >> 16) & (unsigned int)0xFF);
  *(dest + 0) = (uint8_t)((*src >> 24) & (unsigned int)0xFF);
  return;
}

